class Solution:
    def canPartitionGrid(self, grid):
        m = len(grid)
        n = len(grid[0])
        total = sum(sum(row) for row in grid)
        for r in range(1, m):
            top = sum(sum(grid[i]) for i in range(r))
            if top == total - top:
                return True
        for c in range(1, n):
            left = 0
            for i in range(m):
                for j in range(c):
                    left += grid[i][j]
            if left == total - left:
                return True
        return False

