class Solution:
    def canPartitionGrid(self, grid):
        m = len(grid)
        n = len(grid[0])
        total = sum(sum(row) for row in grid)
        if total % 2:
            return False
        half = total // 2
        acc = 0
        for r in range(m - 1):
            acc += sum(grid[r])
            if acc == half:
                return True
        col = [0] * n
        for i in range(m):
            row = grid[i]
            for j in range(n):
                col[j] += row[j]
        acc = 0
        for c in range(n - 1):
            acc += col[c]
            if acc == half:
                return True
        return False

