var canPartitionGrid = function(grid) {
    const m = grid.length, n = grid[0].length;
    let total = 0;
    for (const row of grid) for (const v of row) total += v;
    if (total % 2 !== 0) return false;
    const half = total / 2;
    let acc = 0;
    for (let r = 0; r < m - 1; r++) {
        for (let j = 0; j < n; j++) acc += grid[r][j];
        if (acc === half) return true;
    }
    const col = new Array(n).fill(0);
    for (let i = 0; i < m; i++) for (let j = 0; j < n; j++) col[j] += grid[i][j];
    acc = 0;
    for (let c = 0; c < n - 1; c++) {
        acc += col[c];
        if (acc === half) return true;
    }
    return false;
};
